INSERT INTO `user_info` (`id`, `username`, `password_hash`, `email`, `phone`, `region_id`, `status`, `identity_card`, `role_id`, `last_active_at`, `created_at`, `last_login_at`, `login_count`, `avatar_url`, `bio`, `nickname`, `birthday`, `gender`, `author_tag_id`, `updated_at`, `occupation`, `points`, `experience`, `is_premium_member`, `premium_expiry_date`, `balance`) VALUES
(920001, 'db_01', '$2a$10$JJCD0eHmAaTaBkNhh4juuu1WA.NypYzMfMfa9csnbvkKNahKqpJ1e', 'db_01@demo-it.cn', NULL, 900025, 'active', NULL, 4, '2026-02-08 13:00:00', '2025-11-07 03:00:00', '2026-01-19 13:00:00', 47, NULL, '常驻深圳市，主要负责数据开发工程师相关工作，方向围绕数据库设计、MySQL。最近常写统计回填和缓存边界，遇到慢查询会先看数据分布，不急着怪框架，算是做过几轮完整交付。写文章偏爱把过程、取舍和结果分开记。', '赵子涵', '1994-01-01', 'female', 910406, '2026-02-08 14:00:00', '数据库工程师', 1157, 3520, 1, '2026-07-20 12:00:00', 20),
(920002, 'fe_02', '$2a$10$JJCD0eHmAaTaBkNhh4juuu1WA.NypYzMfMfa9csnbvkKNahKqpJ1e', 'fe_02@demo-it.cn', NULL, 900034, 'active', NULL, 4, '2026-01-18 07:00:00', '2025-11-10 21:00:00', '2026-01-11 07:00:00', 46, NULL, '在杭州市的团队里，主要负责前端开发工程师相关工作，方向围绕Vue、TypeScript。空态、弹层和详情页节奏是我最近关注最多的点，对亮暗主题、信息层级和留白特别上心，算是带过线上版本收尾。遇到问题会先补时间线，再决定先动哪一层。', '钱雨桐', '1995-02-02', 'female', 910203, '2026-01-18 08:00:00', 'Web 前端工程师', 1127, 3451, 0, NULL, 7.5),
(920003, 'py_03', '$2a$10$JJCD0eHmAaTaBkNhh4juuu1WA.NypYzMfMfa9csnbvkKNahKqpJ1e', 'py_03@demo-it.cn', NULL, 900074, 'active', NULL, 4, '2026-02-24 05:00:00', '2025-11-11 02:00:00', '2026-02-04 05:00:00', 45, NULL, '现在主要在西安市做事，主要负责AI应用工程师相关工作，方向围绕AI应用开发、Elasticsearch。经常被拉去一起看 AI 功能的入口设计，喜欢把“模型问题”和“数据问题”拆开看，算是带过线上版本收尾。希望留下来的内容能让同事少走一遍弯路。', '孙宇轩', '1996-03-03', 'male', 910410, '2026-02-24 06:00:00', '智能应用工程师', 1168, 3388, 0, NULL, 15),
(920004, 'db_04', '$2a$10$JJCD0eHmAaTaBkNhh4juuu1WA.NypYzMfMfa9csnbvkKNahKqpJ1e', 'db_04@demo-it.cn', NULL, 900042, 'active', NULL, 4, '2026-02-09 10:00:00', '2025-11-17 01:00:00', '2026-01-28 10:00:00', 44, NULL, '最近的工作重心放在南京市这边，主要负责数据库工程师相关工作，方向围绕数据库设计、SQL。最近常写统计回填和缓存边界，遇到慢查询会先看数据分布，不急着怪框架，算是有几年项目经验。比起空泛总结，我更愿意把具体动作写出来。', '李思源', '1997-04-04', 'male', 910406, '2026-02-09 11:00:00', '数据开发工程师', 1143, 3357, 1, '2026-07-23 12:00:00', 42.5),
(920005, 'jb_05', '$2a$10$JJCD0eHmAaTaBkNhh4juuu1WA.NypYzMfMfa9csnbvkKNahKqpJ1e', 'jb_05@demo-it.cn', NULL, 900022, 'active', NULL, 4, '2025-12-06 06:00:00', '2025-11-14 05:00:00', '2025-12-01 06:00:00', 43, NULL, '白天在广州市写代码，主要负责服务端工程师相关工作，方向围绕Spring Boot、安全与权限。也会参与项目协作链路的接口收口，对 DTO、状态流转和幂等细节比较执着，算是有几年项目经验。做得慢一点没关系，但我不太接受“看着差不多”。', '周若溪', '1998-05-05', 'female', 910201, '2025-12-06 07:00:00', 'Java 后端工程师', 1138, 3364, 0, NULL, 30),
