-- counter_backfill
UPDATE `comment` c
LEFT JOIN (
  SELECT `target_id`, COUNT(*) AS cnt
  FROM `like_record`
  WHERE `target_type` = 'comment'
    AND `target_id` BETWEEN 970001 AND 970999
  GROUP BY `target_id`
) x ON x.`target_id` = c.`id`
SET c.`likes` = COALESCE(x.cnt, 0)
WHERE c.`id` BETWEEN 970001 AND 970999;

UPDATE `blog` b
LEFT JOIN (
  SELECT `target_id`, COUNT(*) AS cnt
  FROM `view_log`
  WHERE `target_type` = 'blog'
    AND `target_id` BETWEEN 960001 AND 960999
  GROUP BY `target_id`
) v ON v.`target_id` = b.`id`
LEFT JOIN (
  SELECT `target_id`, COUNT(*) AS cnt
  FROM `like_record`
  WHERE `target_type` = 'blog'
    AND `target_id` BETWEEN 960001 AND 960999
  GROUP BY `target_id`
) l ON l.`target_id` = b.`id`
LEFT JOIN (
  SELECT `target_id`, COUNT(*) AS cnt
  FROM `collect_record`
  WHERE `target_type` = 'blog'
    AND `target_id` BETWEEN 960001 AND 960999
  GROUP BY `target_id`
) c ON c.`target_id` = b.`id`
SET b.`view_count` = COALESCE(v.cnt, 0),
    b.`like_count` = COALESCE(l.cnt, 0),
    b.`collect_count` = COALESCE(c.cnt, 0)
WHERE b.`id` BETWEEN 960001 AND 960999;

-- validation_queries
SELECT COUNT(*) AS orphan_region_nodes
FROM `region` r
LEFT JOIN `region` p ON p.`id` = r.`parent_id`
WHERE r.`id` BETWEEN 900001 AND 900999
  AND r.`parent_id` IS NOT NULL
  AND p.`id` IS NULL;

SELECT COUNT(*) AS orphan_tag_nodes
FROM `tag` t
LEFT JOIN `tag` p ON p.`id` = t.`parent_id`
WHERE t.`id` BETWEEN 910001 AND 910999
  AND t.`parent_id` IS NOT NULL
  AND p.`id` IS NULL;

SELECT COUNT(*) AS duplicated_region_code_count
FROM (
  SELECT `code`
  FROM `region`
  WHERE `id` BETWEEN 900001 AND 900999
  GROUP BY `code`
  HAVING COUNT(*) > 1
) z;

WITH RECURSIVE tag_path AS (
  SELECT `id`, `parent_id`, CAST(`name` AS CHAR(500)) AS path
  FROM `tag`
  WHERE `id` BETWEEN 910001 AND 910999 AND `parent_id` IS NULL
  UNION ALL
  SELECT t.`id`, t.`parent_id`, CONCAT(tp.path, ' > ', t.`name`) AS path
  FROM `tag` t
  JOIN tag_path tp ON tp.`id` = t.`parent_id`
  WHERE t.`id` BETWEEN 910001 AND 910999
)
SELECT COUNT(*) AS duplicated_tag_path_count
FROM (
  SELECT `path`
  FROM tag_path
  GROUP BY `path`
  HAVING COUNT(*) > 1
) q;

SELECT COUNT(*) AS generated_user_count
FROM `user_info`
WHERE `id` BETWEEN 920001 AND 920999;

SELECT COUNT(*) AS generated_blog_count
FROM `blog`
WHERE `id` BETWEEN 960001 AND 960999;

SELECT COUNT(*) AS generated_circle_count
FROM `circle`
WHERE `id` BETWEEN 940001 AND 940999;

SELECT COUNT(*) AS public_approved_circle_count
FROM `circle`
WHERE `id` BETWEEN 940001 AND 940999
  AND `type` = 'approved'
  AND `visibility` = 'public';

SELECT COUNT(*) AS generated_circle_root_post_count
FROM `circle_comment`
WHERE `id` BETWEEN 980001 AND 980999
  AND `parent_comment_id` IS NULL
  AND `status` = 'published';

SELECT COUNT(*) AS invalid_user_region_ref_count
FROM `user_info` u
LEFT JOIN `region` r ON r.`id` = u.`region_id`
WHERE u.`id` BETWEEN 920001 AND 920999
  AND u.`region_id` IS NOT NULL
  AND r.`id` IS NULL;

SELECT COUNT(*) AS invalid_user_author_tag_ref_count
FROM `user_info` u
LEFT JOIN `tag` t ON t.`id` = u.`author_tag_id`
WHERE u.`id` BETWEEN 920001 AND 920999
  AND u.`author_tag_id` IS NOT NULL
  AND t.`id` IS NULL;

SELECT COUNT(*) AS invalid_user_skill_tag_ref_count
FROM `user_skill` s
LEFT JOIN `tag` t ON t.`id` = s.`tag_id`
WHERE s.`id` BETWEEN 930001 AND 930999
  AND t.`id` IS NULL;

WITH RECURSIVE seq AS (
  SELECT 0 AS n
  UNION ALL
  SELECT n + 1 FROM seq WHERE n < 10
)
SELECT COUNT(*) AS invalid_blog_tag_ref_count
FROM `blog` b
JOIN seq ON seq.n < JSON_LENGTH(b.`tags`)
LEFT JOIN `tag` t ON t.`id` = CAST(JSON_UNQUOTE(JSON_EXTRACT(b.`tags`, CONCAT('$[', seq.n, ']'))) AS UNSIGNED)
WHERE b.`id` BETWEEN 960001 AND 960999
  AND b.`tags` IS NOT NULL
  AND t.`id` IS NULL;

SELECT 0 AS invalid_project_tag_ref_count;

SELECT COUNT(*) AS non_member_circle_post_count
FROM `circle_comment` cc
LEFT JOIN `circle_member` cm
  ON cm.`circle_id` = cc.`circle_id`
 AND cm.`user_id` = cc.`author_id`
 AND cm.`status` = 'active'
WHERE cc.`id` BETWEEN 980001 AND 980999
  AND cm.`id` IS NULL;

SELECT COUNT(*) AS inconsistent_blog_counter_count
FROM `blog` b
LEFT JOIN (
  SELECT `target_id`, COUNT(*) AS view_cnt
  FROM `view_log`
  WHERE `target_type` = 'blog'
  GROUP BY `target_id`
) v ON v.`target_id` = b.`id`
LEFT JOIN (
  SELECT `target_id`, COUNT(*) AS like_cnt
  FROM `like_record`
  WHERE `target_type` = 'blog'
  GROUP BY `target_id`
) l ON l.`target_id` = b.`id`
LEFT JOIN (
  SELECT `target_id`, COUNT(*) AS collect_cnt
  FROM `collect_record`
  WHERE `target_type` = 'blog'
  GROUP BY `target_id`
) c ON c.`target_id` = b.`id`
WHERE b.`id` BETWEEN 960001 AND 960999
  AND (
    b.`view_count` <> COALESCE(v.`view_cnt`, 0)
    OR b.`like_count` <> COALESCE(l.`like_cnt`, 0)
    OR b.`collect_count` <> COALESCE(c.`collect_cnt`, 0)
  );

SELECT COUNT(*) AS invalid_blog_status_count
FROM `blog`
WHERE `id` BETWEEN 960001 AND 960999
  AND `status` NOT IN ('draft', 'pending', 'published', 'rejected');

SELECT COUNT(*) AS invalid_circle_status_count
FROM `circle`
WHERE `id` BETWEEN 940001 AND 940999
  AND `type` NOT IN ('pending', 'approved', 'close', 'rejected');

SELECT COUNT(*) AS invalid_circle_visibility_count
FROM `circle`
WHERE `id` BETWEEN 940001 AND 940999
  AND `visibility` NOT IN ('public', 'private');

SELECT COUNT(*) AS non_published_blog_with_publish_time_count
FROM `blog`
WHERE `id` BETWEEN 960001 AND 960999
  AND `status` <> 'published'
  AND `publish_time` IS NOT NULL;

SELECT COUNT(*) AS duplicated_user_bio_count
FROM (
  SELECT `bio`
  FROM `user_info`
  WHERE `id` BETWEEN 920001 AND 920999
  GROUP BY `bio`
  HAVING COUNT(*) > 1
) x;

SELECT COUNT(*) AS duplicated_blog_title_count
FROM (
  SELECT `title`
  FROM `blog`
  WHERE `id` BETWEEN 960001 AND 960999
  GROUP BY `title`
  HAVING COUNT(*) > 1
) x;

SELECT COUNT(*) AS timeline_inconsistency_count
FROM (
  SELECT s.`id`
  FROM `user_skill` s
  JOIN `user_info` u ON u.`id` = s.`user_id`
  WHERE s.`id` BETWEEN 930001 AND 930999
    AND s.`created_at` < u.`created_at`
  UNION ALL
  SELECT b.`id`
  FROM `blog` b
  JOIN `user_info` u ON u.`id` = b.`author_id`
  WHERE b.`id` BETWEEN 960001 AND 960999
    AND (b.`created_at` < u.`created_at`
         OR (b.`publish_time` IS NOT NULL AND b.`publish_time` < u.`created_at`)
         OR (b.`publish_time` IS NOT NULL AND b.`publish_time` < b.`created_at`))
  UNION ALL
  SELECT c.`id`
  FROM `comment` c
  JOIN `blog` b ON b.`id` = c.`post_id`
  JOIN `user_info` u ON u.`id` = c.`author_id`
  LEFT JOIN `comment` p ON p.`id` = c.`parent_comment_id`
  WHERE c.`id` BETWEEN 970001 AND 970999
    AND (c.`created_at` < u.`created_at`
         OR c.`created_at` < COALESCE(b.`publish_time`, b.`created_at`)
         OR (p.`id` IS NOT NULL AND c.`created_at` < p.`created_at`))
  UNION ALL
  SELECT cc.`id`
  FROM `circle_comment` cc
  JOIN `circle` ci ON ci.`id` = cc.`circle_id`
  JOIN `user_info` u ON u.`id` = cc.`author_id`
  LEFT JOIN `circle_comment` p ON p.`id` = cc.`parent_comment_id`
  WHERE cc.`id` BETWEEN 980001 AND 980999
    AND (cc.`created_at` < ci.`created_at`
         OR cc.`created_at` < u.`created_at`
         OR (p.`id` IS NOT NULL AND cc.`created_at` < p.`created_at`))
  UNION ALL
  SELECT f.`id`
  FROM `follow` f
  JOIN `user_info` u1 ON u1.`id` = f.`follower_id`
  JOIN `user_info` u2 ON u2.`id` = f.`followee_id`
  WHERE f.`id` BETWEEN 990001 AND 990999
    AND (f.`created_at` < u1.`created_at` OR f.`created_at` < u2.`created_at`)
  UNION ALL
  SELECT fr.`id`
  FROM `friendship` fr
  JOIN `user_info` u1 ON u1.`id` = fr.`user1_id`
  JOIN `user_info` u2 ON u2.`id` = fr.`user2_id`
  WHERE fr.`id` BETWEEN 991001 AND 991999
    AND (fr.`request_time` < u1.`created_at`
         OR fr.`request_time` < u2.`created_at`
         OR (fr.`response_time` IS NOT NULL AND fr.`response_time` < fr.`request_time`))
  UNION ALL
  SELECT l.`id`
  FROM `like_record` l
  JOIN `user_info` u ON u.`id` = l.`user_id`
  LEFT JOIN `blog` b ON l.`target_type` = 'blog' AND b.`id` = l.`target_id`
  LEFT JOIN `comment` c ON l.`target_type` = 'comment' AND c.`id` = l.`target_id`
  WHERE l.`id` BETWEEN 992001 AND 992999
    AND (
      l.`created_at` < u.`created_at`
      OR (b.`id` IS NOT NULL AND l.`created_at` < COALESCE(b.`publish_time`, b.`created_at`))
      OR (c.`id` IS NOT NULL AND l.`created_at` < c.`created_at`)
    )
  UNION ALL
  SELECT cr.`id`
  FROM `collect_record` cr
  JOIN `user_info` u ON u.`id` = cr.`user_id`
  JOIN `blog` b ON b.`id` = cr.`target_id`
  WHERE cr.`id` BETWEEN 993001 AND 993999
    AND (cr.`created_at` < u.`created_at`
         OR cr.`created_at` < COALESCE(b.`publish_time`, b.`created_at`))
  UNION ALL
  SELECT v.`id`
  FROM `view_log` v
  LEFT JOIN `user_info` u ON u.`id` = v.`user_id`
  JOIN `blog` b ON v.`target_type` = 'blog' AND b.`id` = v.`target_id`
  WHERE v.`id` BETWEEN 994001 AND 999999
    AND (
      (u.`id` IS NOT NULL AND v.`created_at` < u.`created_at`)
      OR v.`created_at` < COALESCE(b.`publish_time`, b.`created_at`)
    )
) timeline_bad;

COMMIT;
